import { Phase, Spec, PRD, BuildOutput, BuildDispatch } from './types';

export type VerificationStatus = 'Pending' | 'Running' | 'Passed' | 'Failed' | 'Partial' | 'Escalated';

export interface VerificationCheck {
  name: string;
  description: string;
  status: 'pass' | 'fail' | 'warning' | 'skipped';
  details: string;
}

export interface VerificationReport {
  phaseId: string;
  buildOutputId: string;
  status: VerificationStatus;
  checks: VerificationCheck[];
  summary: string;
  escalateToMike: boolean;
  escalationReason: string | null;
  createdAt: string;
}

export function runVerification(
  phase: Phase,
  spec: Spec | null,
  prd: PRD | null,
  buildOutput: BuildOutput | null,
  buildDispatch: BuildDispatch | null
): VerificationReport {
  const checks: VerificationCheck[] = [];

  // Check 1: Build output exists
  checks.push({
    name: 'Build output present',
    description: 'Build output record exists for this phase',
    status: buildOutput ? 'pass' : 'fail',
    details: buildOutput ? 'Build output found' : 'No build output record',
  });

  // Check 2: Build output linked to dispatch
  checks.push({
    name: 'Dispatch linkage',
    description: 'Build output links to a dispatch record',
    status: buildOutput && buildDispatch && buildOutput.buildDispatchId === buildDispatch.id ? 'pass' : buildOutput ? 'warning' : 'skipped',
    details: buildOutput?.buildDispatchId ? 'Linked to dispatch ' + buildOutput.buildDispatchId : 'No linkage',
  });

  // Check 3: Implementation summary present
  checks.push({
    name: 'Implementation summary',
    description: 'Build output has an implementation summary',
    status: buildOutput?.implementationSummary ? 'pass' : 'fail',
    details: buildOutput?.implementationSummary ? 'Summary present (' + buildOutput.implementationSummary.length + ' chars)' : 'No summary',
  });

  // Check 4: Changed files recorded
  checks.push({
    name: 'Changed files recorded',
    description: 'Build output lists changed files',
    status: buildOutput?.artifactLinks && buildOutput.artifactLinks.length > 0 ? 'pass' : 'warning',
    details: buildOutput?.artifactLinks ? buildOutput.artifactLinks.length + ' artifacts' : 'No artifacts',
  });

  // Check 5: Success criteria assessable
  checks.push({
    name: 'Success criteria present',
    description: 'Phase has defined success criteria',
    status: phase.successCriteria ? 'pass' : 'warning',
    details: phase.successCriteria || 'No success criteria defined',
  });

  // Determine overall status
  const failCount = checks.filter(c => c.status === 'fail').length;
  const warnCount = checks.filter(c => c.status === 'warning').length;

  let status: VerificationStatus;
  let escalateToMike = false;
  let escalationReason: string | null = null;

  if (failCount === 0 && warnCount === 0) {
    status = 'Passed';
  } else if (failCount === 0) {
    status = 'Partial';
  } else if (failCount <= 1) {
    status = 'Failed';
    escalateToMike = true;
    escalationReason = failCount + ' check(s) failed: ' + checks.filter(c => c.status === 'fail').map(c => c.name).join(', ');
  } else {
    status = 'Failed';
    escalateToMike = true;
    escalationReason = 'Multiple verification failures';
  }

  return {
    phaseId: phase.id,
    buildOutputId: buildOutput?.id || '',
    status,
    checks,
    summary: failCount + ' failed, ' + warnCount + ' warnings, ' + checks.filter(c => c.status === 'pass').length + ' passed',
    escalateToMike,
    escalationReason,
    createdAt: new Date().toISOString(),
  };
}

